local function phx_safe_merge(tag, fn, ...)
    local args = {...}
    local ok, res = pcall(function() return fn(unpack(args)) end)
    if not ok then
        warn("[PHUCMAX MERGE] " .. tostring(tag) .. " :: " .. tostring(res))
    end
    return ok, res
end

PHUCMAX.Modules.MergeUtils = PHUCMAX.Modules.MergeUtils or {}

function PHUCMAX.Modules.MergeUtils.GetBP(name)
    local p = game.Players.LocalPlayer
    return (p.Backpack and p.Backpack:FindFirstChild(name)) or (p.Character and p.Character:FindFirstChild(name))
end

function PHUCMAX.Modules.MergeUtils.GetInventory()
    local ok, data = pcall(function()
        return game:GetService("ReplicatedStorage").Remotes.CommF_:InvokeServer("getInventory")
    end)
    return ok and data or {}
end

function PHUCMAX.Modules.MergeUtils.GetIn(name)
    for _, item in pairs(PHUCMAX.Modules.MergeUtils.GetInventory()) do
        if type(item) == "table" and item.Name == name then
            return true
        end
    end
    return PHUCMAX.Modules.MergeUtils.GetBP(name) ~= nil
end

function PHUCMAX.Modules.MergeUtils.GetWP(name)
    for _, item in pairs(PHUCMAX.Modules.MergeUtils.GetInventory()) do
        if type(item) == "table" and item.Type == "Sword" and item.Name == name then
            return true
        end
    end
    return PHUCMAX.Modules.MergeUtils.GetBP(name) ~= nil
end

function PHUCMAX.Modules.MergeUtils.GetM(name)
    for _, item in pairs(PHUCMAX.Modules.MergeUtils.GetInventory()) do
        if type(item) == "table" and item.Type == "Material" and item.Name == name then
            return item.Count or 0
        end
    end
    return 0
end

function PHUCMAX.Modules.MergeUtils.CheckBoat()
    for _, v in pairs(workspace.Boats:GetChildren()) do
        if v:FindFirstChild("Owner") and tostring(v.Owner.Value) == tostring(game.Players.LocalPlayer.Name) then
            return v
        end
    end
    return false
end

function PHUCMAX.Modules.MergeUtils.CheckEnemyBoat()
    for _, v in pairs(workspace.Enemies:GetChildren()) do
        if (v.Name == "FishBoat" or v.Name == "PirateBrigade" or v.Name == "PirateGrandBrigade") and v:FindFirstChild("Health") and v.Health.Value > 0 then
            return v
        end
    end
    return false
end

function PHUCMAX.Modules.MergeUtils.CheckSeaEntity(name)
    local sea = workspace:FindFirstChild("SeaBeasts")
    if sea and sea:FindFirstChild(name) then return true end
    for _, v in pairs(workspace.Enemies:GetChildren()) do
        if v.Name == name and ((v:FindFirstChild("Health") and v.Health.Value > 0) or (v:FindFirstChild("Humanoid") and v.Humanoid.Health > 0)) then
            return true
        end
    end
    return false
end

function PHUCMAX.Modules.MergeUtils.StoreFruit()
    local p = game.Players.LocalPlayer
    for _, tool in pairs(p.Backpack:GetChildren()) do
        if tool:IsA("Tool") and string.find(tool.Name, "Fruit") then
            phx_safe_merge("StoreFruit", function()
                game:GetService("ReplicatedStorage").Remotes.CommF_:InvokeServer("StoreFruit", tool:GetAttribute("OriginalName"), tool)
            end)
        end
    end
end

function PHUCMAX.Modules.MergeUtils.DropFruit()
    local p = game.Players.LocalPlayer
    local function dropFrom(container)
        for _, tool in pairs(container:GetChildren()) do
            if string.find(tool.Name, "Fruit") then
                phx_safe_merge("DropFruit", function()
                    if p.PlayerGui.Main.Dialogue.Visible then
                        p.PlayerGui.Main.Dialogue.Visible = false
                    end
                    tool.EatRemote:InvokeServer("Drop")
                end)
            end
        end
    end
    dropFrom(p.Backpack)
    if p.Character then dropFrom(p.Character) end
end

function PHUCMAX.Modules.MergeUtils.CollectFruit()
    local p = game.Players.LocalPlayer
    if not (p.Character and p.Character:FindFirstChild("HumanoidRootPart")) then return end
    for _, v in pairs(workspace:GetChildren()) do
        if string.find(v.Name, "Fruit") and v:FindFirstChild("Handle") then
            v.Handle.CFrame = p.Character.HumanoidRootPart.CFrame
        end
    end
end

function PHUCMAX.Modules.MergeUtils.TpEntrance(pos)
    phx_safe_merge("requestEntrance", function()
        game.ReplicatedStorage.Remotes.CommF_:InvokeServer("requestEntrance", pos)
    end)
end

function PHUCMAX.Modules.MergeUtils.LowCpu()
    local g = game
    local w = g.Workspace
    local l = g.Lighting
    local t = w.Terrain
    t.WaterWaveSize = 0
    t.WaterWaveSpeed = 0
    t.WaterReflectance = 0
    t.WaterTransparency = 0
    l.GlobalShadows = false
    l.FogEnd = 9e9
    l.Brightness = 0
    settings().Rendering.QualityLevel = "Level01"
    for _, v in pairs(g:GetDescendants()) do
        if v:IsA("Part") or v:IsA("Union") or v:IsA("CornerWedgePart") or v:IsA("TrussPart") then
            v.Material = "Plastic"
            v.Reflectance = 0
        elseif v:IsA("Decal") or v:IsA("Texture") then
            v.Transparency = 1
        elseif v:IsA("ParticleEmitter") or v:IsA("Trail") then
            v.Lifetime = NumberRange.new(0)
        elseif v:IsA("Explosion") then
            v.BlastPressure = 1
            v.BlastRadius = 1
        elseif v:IsA("Fire") or v:IsA("SpotLight") or v:IsA("Smoke") or v:IsA("Sparkles") then
            v.Enabled = false
        elseif v:IsA("MeshPart") then
            v.Material = "Plastic"
            v.Reflectance = 0
        end
    end
end

function PHUCMAX.Modules.MergeUtils.Hop(maxPlayers)
    maxPlayers = maxPlayers or 12
    phx_safe_merge("Hop", function()
        local browser = game.ReplicatedStorage:FindFirstChild("__ServerBrowser")
        if not browser then return end
        for page = 1, 50 do
            local ok, remote = pcall(function() return browser:InvokeServer(page) end)
            if ok and type(remote) == "table" then
                for jobId, data in pairs(remote) do
                    if jobId ~= game.JobId and tonumber(data.Count or data["Count"] or 99) < maxPlayers then
                        game:GetService("TeleportService"):TeleportToPlaceInstance(game.PlaceId, jobId)
                        return
                    end
                end
            end
        end
    end)
end

