utils.generatePath = 
    function(...)
        local args = ...;
        local path = ""

        for i, v in ipairs(args) do
            path = (path == "") and v or (path .. "/" .. v)
        end

        return path
    end

utils.makePath = 
    function(...)
        local args = {...}
        local path = utils.generatePath(args)

        if not isfolder(path) then
            makefolder(path)
        end
    end

utils.writeFile = 
    function(path, content)
        if not isfile(path) then
            writefile(path, content)
        end
    end

