utils.GetTextBounds= function(Text, Font, Size, Resolution)
    local Bounds = game:GetService("TextService"):GetTextSize(Text, Size, Font, Resolution or Vector2.new(1920, 1080))
    return { [1] = Bounds.X, [2] = Bounds.Y }
