                        if ToggleFunctions.Enabled == true then
                            ToggleFunctions.Disable()
                        else
                            ToggleFunctions.Enable()
                        end
                    end)
    
                    Toggle.InputBegan:Connect(function(a)
                        if a.UserInputType == Enum.UserInputType then
                            if ToggleFunctions.Enabled == true then
                                ToggleFunctions.Disable()
                            else
                                ToggleFunctions.Enable()
                            end
                        end
                    end)
    
                    return ToggleFunctions
                end
    
