	QuestTitle = QuestGui:FindFirstChild("Container") and QuestGui.Container:FindFirstChild("QuestTitle");
	if not QuestTitle then
		return false;
	end;
	if QuestGui.Visible == true then
		if QuestTitle.Title.Text:find(Y) then
			return true;
		else
			return false;
		end;
	else
		return false;
	end;
end;
